<?phpnamespace App\Helpers;use App\Entity\BienClient;use App\Entity\DocumentExpertise;use App\Entity\DocumentImage;use App\Entity\DocumentPdf;use App\Entity\Expertise;use App\Entity\KohUtilisateur;use App\Entity\MemoBien;use App\Entity\OtherDocument;use App\Entity\OtherInfoBien;use App\Entity\RemarqueBien;use App\Repository\BienClientRepository;use App\Repository\ExpertiseRepository;use App\Repository\KohUtilisateurRepository;use DateTime;use DateTimeImmutable;use DateTimeZone;use Doctrine\Persistence\ObjectManager;use Exception;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\File\UploadedFile;use Symfony\Component\HttpFoundation\Request;class BienClientHelper extends AbstractController{    /**     * @param Request $request     * @param ExpertiseRepository $expertiseRepository     * @return Expertise[]|int|mixed|string     */    public function getExpertiseSorted(Request $request, ExpertiseRepository $expertiseRepository)    {        $sort = $request->get('sort-by');        $type = $request->get('type');        $expertises = [];        if ($sort !== null) {            $expertises = $expertiseRepository->getExpertisesSortBy($sort, $type);        }        if ($sort === null && $type === null) {            $expertises = $expertiseRepository->findBy(array(), array('id' => 'DESC'));        }        return $expertises;    }    /**     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param $user     * @return mixed     */    public function getBienClientSorted(Request $request, BienClientRepository $bienClientRepository, KohUtilisateurRepository $kohUtilisateurRepository, $user)    {        $adminUser = $kohUtilisateurRepository->findOneBy(['structure' => $user->getStructure(), 'isAdmin' => true]);        $sort = $request->get('sort-by');        $type = $request->get('type');        $biens = null;        if ($sort !== null) {            $biens = $bienClientRepository->getBienClientByClientSortBy($sort, $adminUser->getId(), $type);        }        if ($sort === null && $type === null) {            $biens = $bienClientRepository->bien_client($adminUser->getId());        }        return $biens;    }    /**     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param $user     * @return mixed     */    public function getBienClientParticulierSorted(Request $request, BienClientRepository $bienClientRepository, KohUtilisateurRepository $kohUtilisateurRepository, $user)    {        $sort = $request->get('sort-by');        $type = $request->get('type');        $biens = null;        if ($sort !== null) {            $biens = $bienClientRepository->getBienClientByClientSortBy($sort, $user->getId(), $type);        }        if ($sort === null && $type === null) {            $biens = $bienClientRepository->bien_client($user->getId());        }        return $biens;    }    /**     * @param Request $request     * @return array     */    public function getQueryParameter(Request $request): array    {        $parameters = array();        if ($request->get('typeCompte') && $request->get('typeCompte') !== '') {            $parameters['typeClient'] = $request->get('typeCompte');        }        if ($request->get('client') && $request->get('client') !== '') {            $parameters['client'] = $request->get('client');        }        if ($request->get('numeroCompteClientStructure') && $request->get('numeroCompteClientStructure') !== '') {            $parameters['numeroCompteClientStructure'] = $request->get('numeroCompteClientStructure');        }        if ($request->get('tf') && $request->get('tf') !== '') {            $parameters['tf'] = $request->get('tf');        }        if ($request->get('quartierFilter') && $request->get('quartierFilter') !== '') {            $parameters['quartierFilter'] = $request->get('quartierFilter');        }        if ($request->get('regionFilter')) {            $parameters['regionFilter'] = $request->get('regionFilter');        }        if ($request->get('cercleFilter') && $request->get('cercleFilter') !== '') {            $parameters['cercleFilter'] = $request->get('cercleFilter');        }        if ($request->get('numeroExpertise') && $request->get('numeroExpertise') !== '') {            $parameters['numeroExpertise'] = $request->get('numeroExpertise');        }        if ($request->get('numeroMbeyan') && $request->get('numeroMbeyan') !== '') {            $parameters['numeroMbeyan'] = $request->get('numeroMbeyan');        }        if ($request->get('dateFinDation') && $request->get('dateFinDation') !== '') {            $parameters['dateFinDation'] = $request->get('dateFinDation');        }        if ($request->get('dateDebutDation') && $request->get('dateDebutDation') !== '') {            $parameters['dateDebutDation'] = $request->get('dateDebutDation');        }        if ($request->get('dateFinImmobilisation') && $request->get('dateFinImmobilisation') !== '') {            $parameters['dateFinImmobilisation'] = $request->get('dateFinImmobilisation');        }        if ($request->get('dateDebutImmobilisation') && $request->get('dateDebutImmobilisation') !== '') {            $parameters['dateDebutImmobilisation'] = $request->get('dateDebutImmobilisation');        }        if ($request->get('typeDocument') && $request->get('typeDocument') !== '') {            $parameters['typeDocument'] = $request->get('typeDocument');        }        if ($request->get('typeAcquisition') && $request->get('typeAcquisition') !== '') {            $parameters['typeAcquisition'] = $request->get('typeAcquisition');        }        if ($request->get('typeUsageBien') && $request->get('typeUsageBien') !== '') {            $parameters['typeUsageBien'] = $request->get('typeUsageBien');        }        if ($request->get('typeBien') && $request->get('typeBien') !== '') {            $parameters['typeBien'] = $request->get('typeBien');        }        if ($request->get('prixEstimationInf') && $request->get('prixEstimationInf') !== '') {            $parameters['prixEstimationInf'] = $request->get('prixEstimationInf');        }        if ($request->get('prixEstimationSup') && $request->get('prixEstimationSup') !== '') {            $parameters['prixEstimationSup'] = $request->get('prixEstimationSup');        }        if ($request->get('dateInfLastEvaluation') && $request->get('dateInfLastEvaluation') !== '') {            $parameters['dateInfLastEvaluation'] = $request->get('dateInfLastEvaluation');        }        if ($request->get('dateSupLastEvaluation') && $request->get('dateSupLastEvaluation') !== '') {            $parameters['dateSupLastEvaluation'] = $request->get('dateSupLastEvaluation');        }        if ($request->get('dateInfNextEvaluation') && $request->get('dateInfNextEvaluation') !== '') {            $parameters['dateInfNextEvaluation'] = $request->get('dateInfNextEvaluation');        }        if ($request->get('dateSupNextEvaluation') && $request->get('dateSupNextEvaluation') !== '') {            $parameters['dateSupNextEvaluation'] = $request->get('dateSupNextEvaluation');        }        return $parameters;    }    /**     * @param $expertises     * @param $baseUrl     * @return array     */    public function serialiseExpertises($expertises, $baseUrl): array    {        $arrayExpertises = array();        foreach ($expertises as $expertise) {            $arrayExpertises[] = $this->serialiseExpertise($expertise, $baseUrl);        }        return $arrayExpertises;    }    /**     * @param Expertise $expertise     * @param $baseUrl     * @return array|null     */    public function serialiseExpertise(Expertise $expertise, $baseUrl): ?array    {        $arrayExpertise = [];        $isConserved = true;        $arrayExpertise['id'] = $expertise->getId();        $arrayExpertise['numeroExpertise'] = $expertise->getNumeroExpertise();        // TYPE ACQUISITION        $typeAcquisition = $expertise->getTypeAcquisition();        $arrayExpertise['typeAcquisition'] = array(            'id' => $typeAcquisition->getId(),            'name' => $typeAcquisition->getName(),            'isBienForStructure' => $typeAcquisition->getIsBienForStructure()        );        // TYPE BIEN        $typeBien = $expertise->getTypeBien();        $arrayExpertise['typeBien'] = array(            'id' => $typeBien->getId(),            'name' => $typeBien->getName()        );        // TYPE USAGE BIEN        $typeUsageBien = $expertise->getTypeUsageBien();        $arrayExpertise['typeUsageBien'] = array(            'id' => $typeUsageBien->getId(),            'name' => $typeUsageBien->getName()        );        // TYPE DOCUMENT PROPRIETE        $typeDocument = $expertise->getTypeDocumentPropriete();        $arrayExpertise['typeDocumentPropriete'] = array(            'id' => $typeDocument->getId(),            'name' => $typeDocument->getName()        );        $arrayExpertise['latitude'] = (float)$expertise->getLatitude();        $arrayExpertise['longitude'] = (float)$expertise->getLongitude();        if ($arrayExpertise['latitude'] == 0 || $arrayExpertise['longitude'] == 0) {            $isConserved = false;        }        if ($expertise->getDateEvaluation() !== null) {            $arrayExpertise['dateEvaluation'] = $expertise->getDateEvaluation()->format('d/m/Y');        } else {            $arrayExpertise['dateEvaluation'] = '';        }        if ($expertise->getDateNextEvaluation() !== null) {            $arrayExpertise['dateNextEvaluation'] = $expertise->getDateNextEvaluation()->format('d/m/Y');        } else {            $arrayExpertise['dateNextEvaluation'] = '';        }        $arrayExpertise['lastEvaluationPrice'] = $expertise->getLastEvaluationPrice();        $arrayExpertise['superficie'] = $expertise->getSuperficie();        $arrayExpertise['remarque'] = $expertise->getRemarque();        $arrayExpertise['other'] = $expertise->getOther();        $arrayExpertise['isForStructure'] = $expertise->getIsForStructure();        $arrayExpertise['infoProprietaire'] = $expertise->getInfoProprietaire();        if ($expertise->getDateEntree() !== null) {            $arrayExpertise['dateEntree'] = $expertise->getDateEntree()->format('d/m/Y');        } else {            $arrayExpertise['dateEntree'] = '';        }        $arrayExpertise['montantAcquisition'] = $expertise->getMontantAcquisition();        $arrayExpertise['dateSortieImmobilisation'] = $expertise->getDateSortieImmobilisation();        if ($expertise->getDateFinDation() !== null) {            $arrayExpertise['dateFinDation'] = $expertise->getDateFinDation()->format('d/m/Y');        } else {            $arrayExpertise['dateFinDation'] = '';        }        if ($expertise->getIcon() === null) {            $arrayExpertise['icon'] = $baseUrl . '/images/map-logo.png';        } else {            $arrayExpertise['icon'] = $baseUrl . '/images/bien/icons/' . $expertise->getIcon();        }        $arrayExpertise['createdAt'] = $expertise->getCreatedAt()->format('d/m/Y');        $arrayExpertise['updatedAt'] = $expertise->getUpdatedAt() !== null ? $expertise->getUpdatedAt()->format('d/m/Y') : '';        // BIEN CLIENT        $bien = $expertise->getBienClient();        $arrayExpertise['bienClient'] = array(            'id' => $bien->getId(),            'numeroDocument' => $bien->getNumeroDocument(),            'createdAt' => $bien->getCreatedAt()->format('d/m/Y'),            'updatedAt' => $bien->getUpdatedAt() !== null ? $bien->getUpdatedAt()->format('d/m/Y') : '',        );        $kohUtilisateur = $bien->getKohUtilisateur();        $arrayExpertise['bienClient']['kohUtilisateur'] = array(            'id' => $kohUtilisateur->getId(),            'name' => $kohUtilisateur->getFirstName() . ' ' . $kohUtilisateur->getLastName(),            'nomStructure' => $kohUtilisateur->getNomStructure()        );        if ($kohUtilisateur->getTypeCompte()->getIsStructure()) {            $structure = $kohUtilisateur->getStructure();            $arrayExpertise['bienClient']['kohUtilisateur']['structure'] = array(                'id' => $structure->getId(),                'name' => $structure->getName()            );        }        $quartier = $bien->getQuartier();        if ($quartier !== null) {            $arrayExpertise['bienClient']['quartier'] = array(                'id' => $quartier->getId(),                'name' => $quartier->getName(),                'latitude' => $quartier->getLatitude(),                'longitude' => $quartier->getLongitude()            );        } else {            $isConserved = false;        }        $commune = $quartier->getCommune();        if ($commune !== null) {            $arrayExpertise['bienClient']['quartier']['commune'] = array(                'id' => $commune->getId(),                'name' => $commune->getName(),            );            $cercle = $commune->getCercle();            if ($cercle !== null) {                $arrayExpertise['bienClient']['quartier']['commune']['cercle'] = array(                    'id' => $cercle->getId(),                    'name' => $cercle->getName(),                );            } else {                $isConserved = false;            }            $region = $cercle->getRegion();            if ($region !== null) {                $arrayExpertise['bienClient']['quartier']['commune']['cercle']['region'] = array(                    'id' => $region->getId(),                    'name' => $region->getName()                );            } else {                $isConserved = false;            }        } else {            $isConserved = false;        }        $dossierMbeyan = $expertise->getDossierMbeyan();        if ($dossierMbeyan !== null) {            $arrayExpertise['dossierMbeyan'] = array(                'id' => $dossierMbeyan->getId(),                'numeroDossier' => $dossierMbeyan->getNumeroDossier()            );        }        $arrayExpertise['fraisAcquisition'] = $expertise->getFraisAcquisition();        $arrayExpertise['volumeFoncier'] = $expertise->getVolumeFoncier();        $arrayExpertise['foncierF'] = $expertise->getFoncierF();        $clientStructure = $expertise->getClientStructure();        if ($clientStructure !== null) {            $arrayExpertise['clientStructure'] = array(                'id' => $clientStructure->getId(),                'name' => $clientStructure->getName(),                'numeroCompte' => $clientStructure->getNumeroCompte()            );        }        $createdBy = $expertise->getCreatedBy();        if ($createdBy !== null) {            $arrayExpertise['createdBy'] = array(                'id' => $createdBy->getId(),                'name' => $createdBy->getLastName() . ' ' . $createdBy->getFirstName()            );        } else {            $arrayExpertise['createdBy'] = array(                'name' => ''            );        }        $updatedBy = $expertise->getUpdatedBy();        if ($updatedBy !== null) {            $arrayExpertise['updatedBy'] = array(                'id' => $updatedBy->getId(),                'name' => $updatedBy->getLastName() . ' ' . $createdBy->getFirstName()            );        }        return $isConserved ? $arrayExpertise : null;    }    /**     * @param BienClient[] $bienClients     */    public function getLastExpertise(array $bienClients): void    {        foreach ($bienClients as $bienClient) {            $isEmpty = $bienClient->getExpertises()->isEmpty();            if ($isEmpty) {                unset($bienClient);            } else {                $bienClient->setLastExpertise($bienClient->getExpertises()->last());            }        }    }    /**     * @param array $biens     * @param $baseUrl     * @param bool $isForClient     * @return array     */    public function serializeBiens(array $biens, $baseUrl, bool $isForClient = false): array    {        $array_biens = array();        foreach ($biens as $bien) {            $bn = $this->serializeBien($bien, $baseUrl, $isForClient);            if ($bn != null) {                $array_biens[] = $bn;            }        }        return $array_biens;    }    /**     * @param BienClient $bien     * @param $baseUrl     * @param bool $isForClient     * @return array|null     */    public function serializeBien(BienClient $bien, $baseUrl, bool $isForClient = false): ?array    {        if ($bien->getExpertises()->isEmpty()) {            return null;        }        $lastExpertise = $bien->getExpertises()->last();        $bn = array(            'id' => $bien->getId(),            'numero_document' => $bien->getNumeroDocument(),            'numero_expertise' => $lastExpertise->getNumeroExpertise(),            'proprietaire' => $lastExpertise->getInfoProprietaire(),            'prix_derniere_evaluation' => $lastExpertise->getLastEvaluationPrice(),            'last_evaluation_date' => $lastExpertise->getDateEvaluation(),            'next_evaluation_date' => $lastExpertise->getDateNextEvaluation(),            'createdAt' => $lastExpertise->getCreatedAt(),            'superficie' => $lastExpertise->getSuperficie(),            'type_bien' => [                'id' => $lastExpertise->getTypeBien()->getId(),                'libelle' => $lastExpertise->getTypeBien()->getName(),            ],            'usage_bien' => [                'id' => $lastExpertise->getTypeUsageBien()->getId(),                'libelle' => $lastExpertise->getTypeUsageBien()->getName(),            ],            'type_aquisition' => [                'id' => $lastExpertise->getTypeAcquisition()->getId(),                'libelle' => $lastExpertise->getTypeAcquisition()->getName(),                'for_structure' => $lastExpertise->getTypeAcquisition()->getIsBienForStructure()            ],            'koh_utilisateur' => [                'id' => $bien->getKohUtilisateur()->getId(),                'nom' => $bien->getKohUtilisateur()->getFirstName(),                'prenom' => $bien->getKohUtilisateur()->getLastName(),            ],            'dossier_koh' => $lastExpertise->getNumeroExpertise(),            'type_document' => $lastExpertise->getTypeDocumentPropriete()->getName(),            'last_evaluation_price' => $lastExpertise->getLastEvaluationPrice(),            'proprio' => $lastExpertise->getInfoProprietaire(),            'expertiseId' => $lastExpertise->getId()        );        if ($lastExpertise->getCreatedBy() != null) {            $bn['createdBy'] = $lastExpertise->getCreatedBy()->getFirstName() . ' ' . $lastExpertise->getCreatedBy()->getLastName();        } else {            $bn['createdBy'] = '';        }        if ($bien->getQuartier()->getCommune() != null) {            $bn['quartier'] = [                'id' => $bien->getQuartier()->getId(),                'libelle' => $bien->getQuartier()->getName() . '-' . $bien->getQuartier()->getCommune()->getName(),            ];        } else {            $bn['quartier'] = [                'id' => $bien->getQuartier()->getId(),                'libelle' => $bien->getQuartier()->getName(),            ];        }        if ($bien->getQuartier()->getCommune() != null && $bien->getQuartier()->getCommune()->getCercle() != null and $bien->getQuartier()->getCommune()->getCercle()->getRegion() != null) {            $bn['region'] = [                'id' => $bien->getQuartier()->getCommune()->getCercle()->getRegion()->getId(),                'libelle' => $bien->getQuartier()->getCommune()->getCercle()->getRegion()->getName(),            ];            $bn['cercle'] = [                'id' => $bien->getQuartier()->getCommune()->getCercle()->getId(),                'libelle' => $bien->getQuartier()->getCommune()->getCercle()->getName()            ];        }        $cpt = 0;        foreach ($lastExpertise->getdocumentImages() as $img) {            if ($cpt === 0 && $img->getName() !== '') {                $bn['image'] = $img->getName();            }            $cpt++;        }        if (!array_key_exists('image', $bn)) {            $bn['image'] = '';        }        if ($lastExpertise->getDossierMbeyan() !== null) {            $bn['dossier_mbeyan'] = $lastExpertise->getDossierMbeyan()->getNumeroDossier();        } else {            $bn['dossier_mbeyan'] = null;        }        $lat = str_replace(',', '.', $lastExpertise->getLatitude());        $lng = str_replace(',', '.', $lastExpertise->getLongitude());        $bn['latitude'] = $lat;        $bn['longitude'] = $lng;        if ($bien->getKohUtilisateur()->getStructure() !== null) {            $bn['structure'] = [                'id' => $bien->getKohUtilisateur()->getStructure()->getId(),                'nom' => $bien->getKohUtilisateur()->getStructure()->getName(),            ];        } else {            $bn['structure'] = null;        }        if ($lastExpertise->getClientStructure() !== null) {            $bn['client'] = ['id' => $lastExpertise->getClientStructure()->getId(), 'nom' => $lastExpertise->getClientStructure()->getName()];        } else {            $bn['client'] = null;        }        if ($lastExpertise->getDateEntree() !== null) {            $bn['date_entree'] = $lastExpertise->getDateEntree();        } else {            $bn['date_entree'] = null;        }        if ($lastExpertise->getDateFinDation() !== null) {            $bn['date_fin_dation'] = $lastExpertise->getDateFinDation();        } else {            $bn['date_fin_dation'] = null;        }        if ($lastExpertise->getDateSortieImmobilisation() !== null) {            $bn['date_sortie_immobilisation'] = $lastExpertise->getDateSortieImmobilisation();        } else {            $bn['date_sortie_immobilisation'] = null;        }        if ($lastExpertise->getMontantAcquisition() !== null) {            $bn['montant_acquisition'] = $lastExpertise->getMontantAcquisition();        } else {            $bn['montant_acquisition'] = 0;        }        if ($lastExpertise->getFraisAcquisition() !== null) {            $bn['frais_acquisition'] = $lastExpertise->getFraisAcquisition();        } else {            $bn['frais_acquisition'] = 0;        }        $bn['lien'] = $baseUrl . '/super-admin/bien-clients/detail-bien/' . $lastExpertise->getId();        if ($isForClient) {            if ($this->getUser() && $this->getUser()->getTypeCompte()->getIsStructure()) {                $bn['lien'] = $baseUrl . '/admin/bien-clients/structure-detail-bien/' . $lastExpertise->getId();            }            if ($this->getUser() && !$this->getUser()->getTypeCompte()->getIsStructure()) {                $bn['lien'] = $baseUrl . '/admin/bien-clients/particulier-detail-bien/' . $lastExpertise->getId();            }        }        if ($lastExpertise->getIcon() === null) {            $bn['logo'] = $baseUrl . '/images/map-logo.png';        } else {            $bn['logo'] = $baseUrl . '/images/bien/icons/' . $lastExpertise->getIcon();        }        return $bn;    }    /**     * @param Request $request     * @param Expertise $expertise     * @param ObjectManager $entityManager     * @throws Exception     */    public function saveExpertiseFiles(Request $request, Expertise $expertise, ObjectManager $entityManager): void    {        foreach ($request->files as $fileName => $v) {            if ($v !== null && str_contains($fileName, 'document_image')) {                $doc = new DocumentImage();                // TODO REPLACE CODE                $fileF = new UploadedFile($v['tmp_name'], $v['name']);                $doc->setDocumentImage($fileF);                $doc->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')));                $doc->setExpertise($expertise);                $entityManager->persist($doc);                $entityManager->flush();            }            if ($v !== null && str_contains($fileName, 'document_propriete_pdf')) {                $doc = new DocumentPdf();                // $fileF = new UploadedFile($v['tmp_name'], $v['name']);                $doc->setDocumentPdf($v);                $doc->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')));                $doc->setExpertise($expertise);                $entityManager->persist($doc);                $entityManager->flush();            }            if ($v !== null && str_contains($fileName, 'document_expertise_pdf')) {                $doc = new DocumentExpertise();                $doc->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')));                // $fileF = new UploadedFile($v['tmp_name'], $v['name']);                $doc->setDocumentExpertise($v);                $doc->setExpertise($expertise);                $entityManager->persist($doc);                $entityManager->flush();            }            if ($v !== null && str_contains($fileName, 'document_other')) {                $doc = new OtherDocument();                $doc->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')));                // $fileF = new UploadedFile($v['tmp_name'], $v['name']);                $doc->setDocumentFile($v);                $doc->setExpertise($expertise);                $entityManager->persist($doc);                $entityManager->flush();            }        }    }    /**     * @param Request $request     * @param Expertise $expertise     * @param ObjectManager $em     * @param KohUtilisateur $kohUtilisateur     * @return void     * @throws Exception     */    public function saveInformations(Request $request, Expertise $expertise, ObjectManager $em, KohUtilisateur $kohUtilisateur): void    {        if ($request->get('memo') && $request->get('memo') !== '') {            $memo = new MemoBien();            $memo->setContent($request->get('memo'))                ->setCreatedAt(new DateTimeImmutable('now', new DateTimeZone('UTC')))                ->setUpdatedAt(new DateTimeImmutable('now', new DateTimeZone('UTC')))                ->setCreatedBy($kohUtilisateur)                ->setExpertise($expertise);            $em->persist($memo);        }        if ($request->get('remarque') && $request->get('remarque') !== '') {            $remarque = new RemarqueBien();            $remarque->setContent($request->get('remarque'))                ->setCreatedAt(new DateTimeImmutable('now', new DateTimeZone('UTC')))                ->setUpdatedAt(new DateTimeImmutable('now', new DateTimeZone('UTC')))                ->setCreatedBy($kohUtilisateur)                ->setExpertise($expertise);            $em->persist($remarque);        }        if ($request->get('other') && $request->get('other') !== '') {            $other = new OtherInfoBien();            $other->setContent($request->get('other'))                ->setCreatedAt(new DateTimeImmutable('now', new DateTimeZone('UTC')))                ->setUpdatedAt(new DateTimeImmutable('now', new DateTimeZone('UTC')))                ->setCreatedBy($kohUtilisateur)                ->setExpertise($expertise);            $em->persist($other);        }        $em->flush();    }}